#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-05

# Render ASCII patterns from the design system tokens.
# Usage: scripts/render-ascii.sh <pattern> [--set NAME] [--width N] [--label TEXT] [--values CSV]
# Patterns: box, progress-bar, sparkline, tree
# Stubbed (returns 2): swimlane, comparison-table, blast-radius, reversibility-timeline, arrow-flow
# Sets:     default, emphasis, title, soft, portable

set -euo pipefail

SKILL_DIR="${ASCII_SKILL_DIR:-src/skills/ascii-visualizer}"
TOKENS="$SKILL_DIR/tokens.json"

[ -f "$TOKENS" ] || { echo "tokens.json not found at $TOKENS" >&2; exit 1; }
command -v jq >/dev/null 2>&1 || { echo "jq required" >&2; exit 2; }

PATTERN=""
[ $# -gt 0 ] && { PATTERN="$1"; shift; }
SET="default"
WIDTH=40
LABEL=""
VALUES=""

while [ $# -gt 0 ]; do
  case "$1" in
    --set)    SET="$2"; shift 2 ;;
    --width)  WIDTH="$2"; shift 2 ;;
    --label)  LABEL="$2"; shift 2 ;;
    --values) VALUES="$2"; shift 2 ;;
    --help|-h)
      sed -n '2,7p' "$0" | sed 's/^# //'
      exit 0 ;;
    *) echo "unknown flag: $1" >&2; exit 1 ;;
  esac
done

g() { jq -r ".sets.\"$SET\".$1" "$TOKENS"; }
TL=$(g 'corner.tl'); TR=$(g 'corner.tr')
BL=$(g 'corner.bl'); BR=$(g 'corner.br')
H=$(g 'edge.h');     V=$(g 'edge.v')

repeat() { local s="$1" n="$2" out=""; while [ "$n" -gt 0 ]; do out="$out$s"; n=$((n-1)); done; printf '%s' "$out"; }

pad_right() { local s="$1" w="$2" len; len=${#s}; printf '%s' "$s"; [ "$w" -gt "$len" ] && repeat ' ' "$((w - len))"; }

render_box() {
  local inner=$((WIDTH - 2))
  printf '%s%s%s\n' "$TL" "$(repeat "$H" "$inner")" "$TR"
  if [ -n "$LABEL" ]; then
    printf '%s %s%s\n' "$V" "$(pad_right "$LABEL" "$((inner - 1))")" "$V"
  fi
  printf '%s%s%s\n' "$BL" "$(repeat "$H" "$inner")" "$BR"
}

render_progress_bar() {
  local pct="${LABEL:-50}"
  case "$pct" in *%) pct="${pct%\%}" ;; esac
  [ "$pct" -gt 100 ] && pct=100
  [ "$pct" -lt 0 ] && pct=0
  local inner=$((WIDTH - 2))
  local filled=$(( inner * pct / 100 ))
  local empty=$((inner - filled))
  local fill_char empty_char
  if [ "$SET" = "portable" ]; then fill_char="#"; empty_char="-"; else fill_char="█"; empty_char="░"; fi
  printf '[%s%s] %d%%\n' "$(repeat "$fill_char" "$filled")" "$(repeat "$empty_char" "$empty")" "$pct"
}

render_sparkline() {
  local vals="${VALUES:-1,2,3,4,5,6,7,8}"
  local bars=("▁" "▂" "▃" "▄" "▅" "▆" "▇" "█")
  [ "$SET" = "portable" ] && bars=("." "_" "-" "=" "+" "*" "#" "%")
  local out=""
  IFS=',' read -ra arr <<< "$vals"
  local max=0 v
  for v in "${arr[@]}"; do [ "$v" -gt "$max" ] && max="$v"; done
  [ "$max" -eq 0 ] && max=1
  for v in "${arr[@]}"; do
    local idx=$(( v * 7 / max ))
    out="$out${bars[$idx]}"
  done
  printf '%s  %s\n' "$out" "$LABEL"
}

render_tree() {
  local input
  if [ -t 0 ]; then
    input="src/
  api/
    routes.py
    schemas.py
  services/
    billing.py"
  else
    input=$(cat)
  fi
  local tee_r tee_l
  if [ "$SET" = "portable" ]; then tee_r="+"; tee_l="\`"; else tee_r="├"; tee_l="└"; fi
  local lines=()
  while IFS= read -r line; do lines+=("$line"); done <<< "$input"
  local i=0 n=${#lines[@]}
  while [ "$i" -lt "$n" ]; do
    local raw="${lines[$i]}"
    local stripped="${raw#"${raw%%[![:space:]]*}"}"
    local indent=$(( (${#raw} - ${#stripped}) / 2 ))
    local has_sibling=0
    local j=$((i + 1))
    while [ "$j" -lt "$n" ]; do
      local nraw="${lines[$j]}"
      local nstripped="${nraw#"${nraw%%[![:space:]]*}"}"
      local nindent=$(( (${#nraw} - ${#nstripped}) / 2 ))
      if [ "$nindent" -eq "$indent" ]; then has_sibling=1; break; fi
      [ "$nindent" -lt "$indent" ] && break
      j=$((j + 1))
    done
    local prefix=""
    [ "$indent" -gt 0 ] && prefix=$(repeat "  " "$indent")
    if [ "$indent" -eq 0 ]; then
      printf '%s\n' "$stripped"
    elif [ "$has_sibling" -eq 1 ]; then
      printf '%s%s── %s\n' "$prefix" "$tee_r" "$stripped"
    else
      printf '%s%s── %s\n' "$prefix" "$tee_l" "$stripped"
    fi
    i=$((i + 1))
  done
}

case "$PATTERN" in
  box)              render_box ;;
  progress-bar)     render_progress_bar ;;
  sparkline)        render_sparkline ;;
  tree)             render_tree ;;
  swimlane|comparison-table|blast-radius|reversibility-timeline|arrow-flow)
    echo "pattern '$PATTERN' planned for v1.x — not implemented in v1.0.0" >&2
    exit 2 ;;
  ""|--help|-h)
    sed -n '2,7p' "$0" | sed 's/^# //'
    exit 0 ;;
  *)
    echo "unknown pattern: $PATTERN" >&2
    exit 1 ;;
esac
